import pytest
from your_module import parse_email

def test_parse_email_happy_path_simple():
    result = parse_email("user@example.com")
    assert result == {"local": "user", "domain": "example.com"}

def test_parse_email_happy_path_subdomain():
    result = parse_email("john.doe@mail.company.org")
    assert result == {"local": "john.doe", "domain": "mail.company.org"}

def test_parse_email_edge_local_with_symbols():
    result = parse_email("user+tag@example.co.uk")
    assert result == {"local": "user+tag", "domain": "example.co.uk"}

def test_parse_email_none_input():
    assert parse_email(None) is None

def test_parse_email_empty_string():
    assert parse_email("") is None

def test_parse_email_missing_at_symbol():
    assert parse_email("invalidemail.com") is None

def test_parse_email_multiple_at_symbols():
    assert parse_email("a@b@c.com") is None

def test_parse_email_empty_local_part():
    assert parse_email("@example.com") is None

def test_parse_email_empty_domain_part():
    assert parse_email("user@") is None

def test_parse_email_domain_missing_dot():
    assert parse_email("user@examplecom") is None

def test_parse_email_domain_starts_with_dot():
    assert parse_email("user@.example") is None

def test_parse_email_domain_ends_with_dot():
    assert parse_email("user@example.") is None
